  ('social-worker-moex-04433', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '志工人力資源的管理應把握相關的實施原則，其中「使每位志工都有發表意見及提出建議的機會 和權利」，符合下列那種管理原則？', '["建立人事制度", "建立回饋制度", "鼓勵情感交流", "重視訓練發展"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "071fe21ab11a", "answer_pdf_sha1": "ff31968f6db1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04434', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '社會工作者的工作充滿壓力，督導者必須協助工作者保持工作動力，這是屬於下列那種督導角色？', '["行政性督導", "支持性督導", "教育性督導", "調解性督導"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "071fe21ab11a", "answer_pdf_sha1": "ff31968f6db1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04435', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '管理是組織資源以完成工作的過程，若是強調「把事情做對（dothethingright）」係屬於管理概念 中那項重要的要素？', '["資源", "活動或過程", "效率", "效能"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "071fe21ab11a", "answer_pdf_sha1": "ff31968f6db1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04436', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '衝突管理思想有不同的觀點，若認為衝突是無法避免，對團體是有助益且是必要的，最有效的方 式是將衝突納入制度規範，建立完整的管理制度。係屬於下列那種觀點？', '["衝突的行為觀點", "衝突的功能觀點", "衝突的失能性觀點", "衝突的人際觀點"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "071fe21ab11a", "answer_pdf_sha1": "ff31968f6db1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04437', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '定期檢討預算，在過程中進行修正與調整，以確保組織能達成年度目標。下列何者不是定期檢討 預算之目的？', '["審慎預估未來可能的經費收入", "檢討各項活動達成的進度", "掌握支出的重點項目，並加強管理", "比較實際數與預算數，評估績效表現"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "071fe21ab11a", "answer_pdf_sha1": "ff31968f6db1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04438', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '在社工職場中管理者時常面臨倫理兩難問題，下列何者不是常見恪守倫理的原則？', '["對專業負責：對實務工作者及專業發展有所貢獻", "對個案和重要他人負責：為案主系統與其利害關係人之長期福祉服務", "對自己負責：包括真誠的舉止、追求知識與個人的成長", "對社工人員之家庭負責：為社工人員家庭系統之關係負責"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "071fe21ab11a", "answer_pdf_sha1": "ff31968f6db1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-04439', 'social-worker', 'social-worker-moex-110-f2e04173', 'sub-social-worker-05', NULL, 'single_choice', '關於組織員工層級之工作內容及分類，下列敘述何者錯誤？', '["社工員與組員為基層員工，直接負責某項工作或任務", "督導與組長為基層管理者，工作任務包含確保績效能達所定目標", "主任與處長為中階管理者，領導與監督基層員工為工作內容之一", "秘書長與執行長為高階管理者，工作任務含規劃組織長期方向"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:26+00:00", "source_pdf_sha1": "071fe21ab11a", "answer_pdf_sha1": "ff31968f6db1", "source_family": "moex-gov-tw", "moex": {"exam_code": "110111", "c": "105", "s": "0403", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會工作管理", "year": "110", "exam_name": "第二梯次:110年第二次專技人員高等考試中醫師考試分階段考試、營養師、社會工作師考試、110年專技人員高等考試心理師、法醫師、語言治療師、聽...", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
